CREATE OR REPLACE FUNCTION public.send_telegram_notification_on_transaction()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_settings RECORD;
    v_telegram_url TEXT;
    v_message TEXT;
    v_amount_formatted TEXT;
    v_transaction_type TEXT;
    v_http_request_id BIGINT;
    v_chat_id TEXT;
    v_success_count INTEGER := 0;
    v_error_count INTEGER := 0;
BEGIN
    -- Determine transaction type based on table name
    IF TG_TABLE_NAME = 'debit_amount' THEN
        v_transaction_type := 'debit';
        v_amount_formatted := '+' || TO_CHAR(NEW.amount, 'FM999,999,999,999') || ' ' || COALESCE(NEW.currency, 'VND');
    ELSIF TG_TABLE_NAME = 'credit_amount' THEN
        v_transaction_type := 'credit';
        v_amount_formatted := '-' || TO_CHAR(NEW.amount, 'FM999,999,999,999') || ' ' || COALESCE(NEW.currency, 'VND');
    ELSE
        -- Unknown table, skip
        RETURN NEW;
    END IF;

    -- Get user settings
    SELECT 
        telegram_enabled,
        telegram_bot_token,
        telegram_chat_id,
        telegram_send_on_debit,
        telegram_send_on_credit,
        telegram_message_template
    INTO v_user_settings
    FROM user_settings
    LIMIT 1;

    -- Check if Telegram is enabled
    IF v_user_settings.telegram_enabled IS NOT TRUE THEN
        RAISE NOTICE 'Telegram notifications disabled';
        RETURN NEW;
    END IF;

    -- Check if bot token is configured
    IF v_user_settings.telegram_bot_token IS NULL THEN
        RAISE NOTICE 'Telegram bot token not configured';
        RETURN NEW;
    END IF;

    -- Check if chat IDs are configured
    IF v_user_settings.telegram_chat_id IS NULL OR array_length(v_user_settings.telegram_chat_id, 1) IS NULL THEN
        RAISE NOTICE 'No Telegram chat IDs configured';
        RETURN NEW;
    END IF;

    -- Check if we should send for this transaction type
    IF v_transaction_type = 'debit' AND v_user_settings.telegram_send_on_debit IS NOT TRUE THEN
        RAISE NOTICE 'Debit notifications disabled';
        RETURN NEW;
    END IF;

    IF v_transaction_type = 'credit' AND v_user_settings.telegram_send_on_credit IS NOT TRUE THEN
        RAISE NOTICE 'Credit notifications disabled';
        RETURN NEW;
    END IF;

    -- Format message using template (once for all chat IDs)
    v_message := COALESCE(v_user_settings.telegram_message_template, 
                         E'🔔 {app_name}\n💰 Amount: {amount}\n📝 {body}');
    
    -- Replace placeholders
    v_message := REPLACE(v_message, '{app_name}', COALESCE(NEW.app_name, 'Unknown App'));
    v_message := REPLACE(v_message, '{amount}', v_amount_formatted);
    v_message := REPLACE(v_message, '{body}', COALESCE(NEW.body, ''));
    v_message := REPLACE(v_message, '{battery}', '');

    -- Build Telegram API URL
    v_telegram_url := 'https://api.telegram.org/bot' || v_user_settings.telegram_bot_token || '/sendMessage';

    -- Loop through all chat IDs and send message to each
    FOREACH v_chat_id IN ARRAY v_user_settings.telegram_chat_id
    LOOP
        -- Skip empty chat IDs
        IF v_chat_id IS NULL OR trim(v_chat_id) = '' THEN
            CONTINUE;
        END IF;

        -- Send HTTP POST request to Telegram for this chat ID
        BEGIN
            SELECT net.http_post(
                url := v_telegram_url,
                headers := '{"Content-Type": "application/json"}'::jsonb,
                body := jsonb_build_object(
                    'chat_id', v_chat_id,
                    'text', v_message,
                    'parse_mode', 'HTML'
                )
            ) INTO v_http_request_id;

            v_success_count := v_success_count + 1;
            RAISE NOTICE 'Telegram notification sent to chat_id % for % transaction. Request ID: %', 
                         v_chat_id, v_transaction_type, v_http_request_id;
        EXCEPTION WHEN OTHERS THEN
            -- Log error but continue to next chat ID
            v_error_count := v_error_count + 1;
            RAISE WARNING 'Failed to send Telegram notification to chat_id %: %', v_chat_id, SQLERRM;
        END;
    END LOOP;

    -- Final summary
    RAISE NOTICE 'Telegram notification summary: % successful, % failed out of % chat IDs', 
                 v_success_count, v_error_count, array_length(v_user_settings.telegram_chat_id, 1);

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$function$
